// ─── Obtener datos de nodos anteriores ──────────────────────────────────────
const input      = $('Webhook').item.json;
const rfResult   = $('RF Predict').item.json;    // { p_base: 0.401827 }
const ivsmResult = $('IVSM Supabase').item.json; // Array | Object

// p_base del modelo RF (predicción de riesgo cardiorrespiratorio)
const p_base = parseFloat(rfResult.p_base);

// ivsm_score: Supabase REST devuelve array [{ivsm_score, nombre}]
const ivsmArr    = Array.isArray(ivsmResult) ? ivsmResult : [ivsmResult];
const ivsmRow    = ivsmArr.length > 0 ? ivsmArr[0] : null;
const ivsm_score = ivsmRow ? parseFloat(ivsmRow.ivsm_score) : 0.30; // fallback media nacional
const municipio  = ivsmRow ? ivsmRow.nombre : null;

// ─── Fórmula de síntesis SIAT-SM ────────────────────────────────────────────
// RT = 0.55 · P_Base  +  0.20 · IVSM  +  0.25 · (P_Base × IVSM)
const riesgo_total = 0.55 * p_base + 0.20 * ivsm_score + 0.25 * (p_base * ivsm_score);

// ─── Clasificación ──────────────────────────────────────────────────────────
let categoria, tipo_alerta, descripcion, recomendacion;

if (riesgo_total >= 0.65) {
  categoria     = 'critica';
  tipo_alerta   = 'ALERTA CRÍTICA';
  descripcion   = 'Riesgo cardiorrespiratorio muy elevado.';
  recomendacion = 'Consulte con su médico en las próximas 24h. Evite esfuerzos físicos y exposición a contaminantes.';
} else if (riesgo_total >= 0.45) {
  categoria     = 'preventiva';
  tipo_alerta   = 'ALERTA PREVENTIVA';
  descripcion   = 'Riesgo moderado-alto. Se recomienda seguimiento médico próximo.';
  recomendacion = 'Solicite cita médica en los próximos días. Reduzca el tabaquismo y mejore la actividad física.';
} else if (riesgo_total >= 0.25) {
  categoria     = 'informativa';
  tipo_alerta   = 'ALERTA INFORMATIVA';
  descripcion   = 'Riesgo moderado. Hábitos de vida susceptibles de mejora.';
  recomendacion = 'Mejore la dieta, incremente la actividad física y reduzca el consumo de alcohol.';
} else {
  categoria     = 'sin_alerta';
  tipo_alerta   = 'SIN ALERTA';
  descripcion   = 'Riesgo cardiorrespiratorio bajo en las condiciones actuales.';
  recomendacion = 'Mantenga sus hábitos saludables y realice revisiones periódicas.';
}

// ─── Respuesta ───────────────────────────────────────────────────────────────
return [{ json: {
  p_base:       Math.round(p_base       * 1e6) / 1e6,
  ivsm_score:   Math.round(ivsm_score   * 1e6) / 1e6,
  riesgo_total: Math.round(riesgo_total * 1e6) / 1e6,
  categoria,
  tipo_alerta,
  descripcion,
  recomendacion,
  municipio,
  codigo_ine: input.codigo_ine ?? null,
}}];
